BEGIN;
TRUNCATE TABLE
  quiz_attempt_answers,quiz_attempts,quiz_weak_areas,quiz_rewards,
  quiz_options,quiz_questions,quizzes,
  lesson_attachments,lesson_progress,enrollments,
  purchases,reviews,lessons,courses,users
RESTART IDENTITY CASCADE;

-- USERS (50)

-- COURSES (50)

-- LESSONS (1000)

-- LESSON ATTACHMENTS (500)

-- QUIZZES (300)

-- QUIZ QUESTIONS (900)

-- QUIZ OPTIONS (3600)

-- QUIZ REWARDS (1200)

-- PURCHASES (440)

-- ENROLLMENTS (500)

-- LESSON PROGRESS (6450)

-- QUIZ ATTEMPTS (500)

-- QUIZ ATTEMPT ANSWERS (500)

-- QUIZ WEAK AREAS (167)

-- REVIEWS (450)

SELECT setval('users_id_seq',(SELECT MAX(id) FROM users));
SELECT setval('courses_id_seq',(SELECT MAX(id) FROM courses));
SELECT setval('lessons_id_seq',(SELECT MAX(id) FROM lessons));
SELECT setval('lesson_attachments_id_seq',(SELECT MAX(id) FROM lesson_attachments));
SELECT setval('quizzes_id_seq',(SELECT MAX(id) FROM quizzes));
SELECT setval('quiz_questions_id_seq',(SELECT MAX(id) FROM quiz_questions));
SELECT setval('quiz_options_id_seq',(SELECT MAX(id) FROM quiz_options));
SELECT setval('quiz_rewards_id_seq',(SELECT MAX(id) FROM quiz_rewards));
SELECT setval('purchases_id_seq',(SELECT MAX(id) FROM purchases));
SELECT setval('enrollments_id_seq',(SELECT MAX(id) FROM enrollments));
SELECT setval('lesson_progress_id_seq',(SELECT MAX(id) FROM lesson_progress));
SELECT setval('quiz_attempts_id_seq',(SELECT MAX(id) FROM quiz_attempts));
SELECT setval('quiz_attempt_answers_id_seq',(SELECT MAX(id) FROM quiz_attempt_answers));
SELECT setval('quiz_weak_areas_id_seq',(SELECT MAX(id) FROM quiz_weak_areas));
SELECT setval('reviews_id_seq',(SELECT MAX(id) FROM reviews));

COMMIT;

SELECT 'Seed complete!' AS result,
  (SELECT COUNT(*) FROM users)                AS users,
  (SELECT COUNT(*) FROM courses)              AS courses,
  (SELECT COUNT(*) FROM lessons)              AS lessons,
  (SELECT COUNT(*) FROM lesson_attachments)   AS attachments,
  (SELECT COUNT(*) FROM quizzes)              AS quizzes,
  (SELECT COUNT(*) FROM quiz_questions)       AS questions,
  (SELECT COUNT(*) FROM quiz_options)         AS options,
  (SELECT COUNT(*) FROM quiz_rewards)         AS rewards,
  (SELECT COUNT(*) FROM purchases)            AS purchases,
  (SELECT COUNT(*) FROM enrollments)          AS enrollments,
  (SELECT COUNT(*) FROM lesson_progress)      AS lesson_progress,
  (SELECT COUNT(*) FROM quiz_attempts)        AS quiz_attempts,
  (SELECT COUNT(*) FROM quiz_attempt_answers) AS answers,
  (SELECT COUNT(*) FROM quiz_weak_areas)      AS weak_areas,
  (SELECT COUNT(*) FROM reviews)              AS reviews;